(1, 'BDM Intern', 'fa-solid fa-handshake', 'bdm-intern-may-2026', 'Business Development', 'Internship', 'Hybrid (as agreed)', 'Hybrid', 'Intern / Fresher', 0, 1, 'Pursuing or completed a bachelor\'s degree in Business Administration, Marketing, Commerce, or a related field.', 'Strong communication and interpersonal skills; comfortable with email and phone outreach; MS Excel / Google Sheets; curiosity about B2B sales and partnerships; organized and detail-oriented.', 'Support lead research and list building; assist with CRM updates and follow-ups; help prepare decks and meeting notes; shadow calls and demos where appropriate; contribute to partner and client outreach campaigns under supervision.', '<p><strong>Working hours:</strong> 10:00 AM – 4:00 PM (6 hours per day), Monday to Friday.</p><p><strong>Apply by:</strong> 30 May 2026.</p><p>Join HilDes as a Business Development intern and learn how we position AI, SaaS, and MVP offerings to clients. You will work closely with senior BD team members on pipeline hygiene, outreach sequences, and market mapping.</p><p><strong>What you will learn:</strong> Pipeline research, outreach messaging, CRM hygiene, and how BD supports AI, SaaS, and MVP engagements at HilDes.</p>', 'Stipend (discussed at interview)', 'open', '2026-05-30', '2026-05-01 00:26:31', '2026-05-01 00:26:31', '2026-05-01 00:35:02'),
(2, 'Digital Marketing Intern', 'fa-solid fa-bullhorn', 'digital-marketing-intern-may-2026', 'Marketing', 'Internship', 'Hybrid (as agreed)', 'Hybrid', 'Intern / Fresher', 0, 1, 'Pursuing or completed a bachelor\'s in Marketing, Communications, Media, or a related field.', 'Basic understanding of SEO, social media, and content formats; familiarity with Canva or similar tools; good writing in English; willingness to learn analytics and campaign reporting.', 'Assist with social content scheduling and drafts; support on-page SEO checks and content updates; help track campaign metrics; contribute to email and landing page copy reviews; support event and launch announcements.', '<p><strong>Working hours:</strong> 10:00 AM – 4:00 PM (6 hours per day), Monday to Friday.</p><p><strong>Apply by:</strong> 30 May 2026.</p><p>Support HilDes marketing across organic channels, campaigns, and brand touchpoints for AI, SaaS, and software services. Ideal if you want hands-on experience with modern growth stacks.</p><p><strong>What you will learn:</strong> Organic growth tactics, campaign reporting, on-page SEO checks, and content workflows for technology products.</p>', 'Stipend (discussed at interview)', 'open', '2026-05-30', '2026-05-01 00:26:31', '2026-05-01 00:26:31', '2026-05-01 00:35:02');

