"areaServed\": [\n                {\n                    \"@type\": \"Country\",\n                    \"name\": \"United States\"\n                },\n                {\n                    \"@type\": \"Country\",\n                    \"name\": \"United Kingdom\"\n                },\n                {\n                    \"@type\": \"Country\",\n                    \"name\": \"Canada\"\n                },\n                {\n                    \"@type\": \"Country\",\n                    \"name\": \"Germany\"\n                },\n                {\n                    \"@type\": \"Country\",\n                    \"name\": \"United Arab Emirates\"\n                }\n            ],\n            \"offers\": {\n                \"@type\": \"Offer\",\n                \"price\": \"Custom\",\n                \"priceCurrency\": \"USD\",\n                \"availability\": \"https://schema.org/InStock\"\n            }\n        },\n        {\n            \"@type\": \"FAQPage\",\n            \"mainEntity\": [\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Which e-commerce platform is best for my business?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>It depends on your needs. Shopify is ideal for fast launch, WooCommerce for flexibility, and custom solutions for scalability.</p>\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Can you build a fully custom e-commerce platform?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>Yes, we build custom and headless commerce systems tailored to your business model.</p>\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Do you integrate payment gateways?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>Yes, we integrate Stripe, PayPal, and other global payment systems securely.</p>\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Will my store be mobile optimized?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>Absolutely. All stores are built mobile-first for maximum conversions.</p>\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Can you improve my existing store?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>Yes, we optimize speed, UX, and conversion rates of existing e-commerce platforms.</p>\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Do you help increase sales?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>Yes, we focus on conversion rate optimization, UX flow, and performance improvements.</p>\"\n                    }\n                }\n            ]\n        }\n    ]\n}', '2026-04-23 01:53:02', '2026-04-23 10:39:46'),
(8, 'App\\Models\\ServicePage', 8, 1, 1, 1, 'ui-ux-design', 'https://www.hildes.io/ui-ux-design', 'UI UX Design Services Company | SaaS & Web Design Experts | HilDes', 'HilDes provides UI/UX design services for SaaS, web, and mobile applications. We design user-centered interfaces that improve engagement, usability, and conversion rates for global businesses.', 'UI UX design company, SaaS UI UX design, web app design services, product design agency, Figma design services, dashboard UI design, UX optimization services, hire UI UX designers', NULL, NULL, NULL, 'index,follow', NULL, 'UI/UX Design Services | HilDes', 'User-centered UI/UX design for SaaS, web, and mobile apps that improves engagement and conversions.', NULL, NULL, 'https://www.hildes.io/assets/og/ui-ux-design.jpg', 'UI/UX Design Services | HilDes', 'Modern UI/UX design for SaaS and web applications focused on usability, engagement, and conversions.', 'https://www.hildes.io/assets/og/ui-ux-design.jpg', NULL, '{\n    \"@context\": \"https://schema.org\",\n    \"@graph\": [\n        {\n            \"@type\": \"Service\",\n            \"name\": \"UI/UX Design\",\n            \"provider\": {\n                \"@type\": \"Organization\",\n                \"name\": \"HilDes\",\n                \"url\": \"https://www.hildes.io\",\n                \"address\": {\n                    \"@type\": \"PostalAddress\",\n                    \"addressLocality\": \"Lahore\",\n                    \"addressCountry\": \"Pakistan\"\n                }\n            },\n            \"serviceType\": \"UI UX Design\",\n            \"url\": \"https://www.hildes.io/ui-ux-design\",\n            \"description\": \"HilDes provides UI/UX design services for SaaS, web, and mobile applications focused on usability, conversion optimization, and modern user experience design.\",\n            \"areaServed\": [\n                {\n                    \"@type\": \"Country\",\n                    \"name\": \"United States\"\n                },\n                {\n                    \"@type\": \"Country\",\n                    \"name\": \"United Kingdom\"\n                },\n                {\n                    \"@type\": \"Country\",\n                    \"name\": \"Canada\"\n                },\n                {\n                    \"@type\": \"Country\",\n                    \"name\": \"Germany\"\n                },\n                {\n                    \"@type\": \"Country\",\n                    \"name\": \"United Arab Emirates\"\n                }\n            ],\n            \"offers\": {\n                \"@type\": \"Offer\",\n                \"price\": \"Custom\",\n                \"priceCurrency\": \"USD\",\n                \"availability\": \"https://schema.org/InStock\"\n            }\n        },\n        {\n            \"@type\": \"FAQPage\",\n            \"mainEntity\": [\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"What is UI/UX design?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>UI/UX design is the process of creating user interfaces and experiences that are easy to use, visually appealing, and conversion-focused.</p>\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Why is UI/UX important?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>Good UI/UX improves user engagement, reduces bounce rates, and increases conversions and retention.</p>\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Do you design SaaS dashboards?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>Yes, we specialize in SaaS dashboards and complex data-driven interfaces.</p>\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Do you also implement the design?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>Yes, we collaborate with developers to ensure smooth implementation.</p>\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"What tools do you use?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>We primarily use Figma for design systems, wireframes, and prototyping.</p>\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Can you improve existing designs?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>Yes, we redesign and optimize existing products for better usability and conversions.</p>\"\n                    }\n                }\n            ]\n        }\n    ]\n}', '2026-04-23 01:54:02', '2026-04-23 10:43:54');
