(9, 'App\\Models\\ServicePage', 9, 1, 1, 1, 'api-development', 'https://www.hildes.io/api-development', 'API Development & Integration Services | Secure Scalable APIs | HilDes', 'HilDes provides API development and integration services including REST APIs, GraphQL, third-party integrations, and microservices architecture. Connect systems, automate workflows, and scale your business with secure APIs.', 'API development company, REST API development, GraphQL API services, system integration services, third-party API integration, microservices architecture, secure API development, backend API developers', NULL, NULL, NULL, 'index,follow', NULL, 'API Development & Integration Services | HilDes', 'Build secure, scalable APIs and integrate systems to automate workflows and connect your entire digital ecosystem.', NULL, NULL, 'https://www.hildes.io/assets/og/api-development.jpg', 'API Development & Integration Services | HilDes', 'Secure, scalable API development and system integration services for modern businesses.', 'https://www.hildes.io/assets/og/api-development.jpg', NULL, '{\n    \"@context\": \"https://schema.org\",\n    \"@graph\": [\n        {\n            \"@type\": \"Service\",\n            \"name\": \"API Development & Integrations\",\n            \"provider\": {\n                \"@type\": \"Organization\",\n                \"name\": \"HilDes\",\n                \"url\": \"https://www.hildes.io\",\n                \"address\": {\n                    \"@type\": \"PostalAddress\",\n                    \"addressLocality\": \"Lahore\",\n                    \"addressCountry\": \"Pakistan\"\n                }\n            },\n            \"serviceType\": \"API Development and System Integrations\",\n            \"url\": \"https://www.hildes.io/api-development\",\n            \"description\": \"HilDes provides API development and integration services including REST APIs, GraphQL APIs, microservices, and third-party integrations to automate workflows and connect systems.\",\n            \"areaServed\": [\n                {\n                    \"@type\": \"Country\",\n                    \"name\": \"United States\"\n                },\n                {\n                    \"@type\": \"Country\",\n                    \"name\": \"United Kingdom\"\n                },\n                {\n                    \"@type\": \"Country\",\n                    \"name\": \"Canada\"\n                },\n                {\n                    \"@type\": \"Country\",\n                    \"name\": \"Germany\"\n                },\n                {\n                    \"@type\": \"Country\",\n                    \"name\": \"United Arab Emirates\"\n                }\n            ],\n            \"offers\": {\n                \"@type\": \"Offer\",\n                \"price\": \"Custom\",\n                \"priceCurrency\": \"USD\",\n                \"availability\": \"https://schema.org/InStock\"\n            }\n        },\n        {\n            \"@type\": \"FAQPage\",\n            \"mainEntity\": [\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"What is API development?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>API development involves building systems that allow different applications to communicate and exchange data securely.</p>\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"What types of APIs do you build?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>We build REST APIs, GraphQL APIs, and custom microservice-based APIs.</p>\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Can you integrate third-party services?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>Yes, we integrate CRMs, payment gateways, SaaS tools, and enterprise systems.</p>\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Are your APIs secure?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>Yes, we implement authentication, encryption, and security best practices in all APIs.</p>\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Can you improve existing APIs?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>Yes, we optimize and scale existing APIs for performance and reliability.</p>\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Do you provide API documentation?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>Yes, we deliver complete developer-friendly API documentation and version control.</p>\"\n                    }\n                }\n            ]\n        }\n    ]\n}', '2026-04-23 01:55:15', '2026-04-23 10:47:39'),
