(11, 'App\\Models\\CaseStudy', 2, 1, 1, 1, 'enterprise-hr-platform-stabilization-and-scaling', 'http://localhost/case-studies/enterprise-hr-platform-stabilization-and-scaling', 'Enterprise HR Platform Stabilization & Scaling Case Study | HilDes', 'See how HilDes transformed a failing enterprise HR platform into a secure, scalable, high-performance system with 99.9% uptime and sub-2s response times.', 'enterprise HR case study, platform stabilization, AWS scaling, DevOps case study, CI CD implementation, performance optimization, HilDes', NULL, NULL, 'enterprise hr platform stabilization case study', 'index,follow', NULL, 'Enterprise HR Platform Stabilization & Scaling | Case Study', 'From instability to enterprise-grade reliability: infrastructure redesign, DevOps pipelines, security hardening, and major performance gains.', NULL, NULL, NULL, 'Enterprise HR Platform Stabilization & Scaling | HilDes', 'A real transformation case study: 99.9% uptime, better security, automated delivery, and response time reduced to <2s.', NULL, NULL, '{\r\n    \"@context\": \"https://schema.org\",\r\n    \"@graph\": [\r\n        {\r\n            \"@type\": \"Article\",\r\n            \"headline\": \"Enterprise HR Platform Stabilization & Scaling\",\r\n            \"description\": \"Case study of stabilizing and scaling a failing enterprise HR platform.\",\r\n            \"author\": {\r\n                \"@type\": \"Organization\",\r\n                \"name\": \"HilDes\"\r\n            }\r\n        }\r\n    ]\r\n}', '2026-04-23 08:15:50', '2026-04-23 11:28:43'),
(12, 'App\\Models\\CaseStudy', 3, 1, 1, 1, 'high-volume-recruitment-job-portal', 'http://localhost/case-studies/high-volume-recruitment-job-portal', 'High-Volume Recruitment Job Portal Case Study | HilDes', 'Discover how HilDes delivered a conversion-driven recruitment platform generating 400+ qualified applicants daily with scalable cloud architecture.', 'job portal case study, recruitment platform, google ads integration, applicant tracking, lead deduplication, hildes', NULL, NULL, 'high volume recruitment job portal case study', 'index,follow', NULL, 'High-Volume Recruitment Job Portal | Case Study', 'A scalable recruitment engine for high-volume applicant generation and campaign attribution.', NULL, NULL, NULL, 'High-Volume Recruitment Job Portal | HilDes', 'Case study: 400+ qualified applicants daily with a scalable conversion-driven platform.', NULL, NULL, '{\r\n    \"@context\": \"https://schema.org\",\r\n    \"@graph\": [\r\n        {\r\n            \"@type\": \"Article\",\r\n            \"headline\": \"High-Volume Recruitment Job Portal\",\r\n            \"description\": \"Case study of building a scalable recruitment job portal and paid funnel integration.\",\r\n            \"author\": {\r\n                \"@type\": \"Organization\",\r\n                \"name\": \"HilDes\"\r\n            }\r\n        }\r\n    ]\r\n}', '2026-04-23 09:15:42', '2026-04-23 11:32:12'),
(13, 'App\\Models\\CaseStudy', 4, 1, 1, 1, 'ai-voice-interview-system', 'http://localhost/case-studies/ai-voice-interview-system', 'AI Voice Interview System Case Study | HilDes', 'Explore how HilDes built an autonomous AI voice interview system for high-volume, unbiased candidate screening and real-time scoring.', 'AI voice interview, autonomous hiring, recruitment automation, GPT interview system, Twilio Deepgram integration, HilDes case study', NULL, NULL, 'ai voice interview system case study', 'index,follow', NULL, 'AI Voice Interview System | Case Study', 'A real-world AI hiring platform with autonomous interviews, real-time scoring, and scalable concurrent sessions.', NULL, NULL, NULL, 'AI Voice Interview System | HilDes', 'Case study on autonomous candidate screening with AI voice interviews and scalable hiring operations.', NULL, NULL, '{\r\n    \"@context\": \"https://schema.org\",\r\n    \"@graph\": [\r\n        {\r\n            \"@type\": \"Article\",\r\n            \"headline\": \"AI Voice Interview System\",\r\n            \"description\": \"Case study of an autonomous AI voice interview and candidate evaluation platform.\",\r\n            \"author\": {\r\n                \"@type\": \"Organization\",\r\n                \"name\": \"HilDes\"\r\n            }\r\n        }\r\n    ]\r\n}', '2026-04-23 09:18:31', '2026-04-23 11:37:28'),
(14, 'App\\Models\\ServicePage', 10, 1, 1, 1, 'mobile-app-development', 'https://www.hildes.io/mobile-app-development', 'Mobile App Development Company | iOS & Android Apps | HilDes', 'HilDes provides mobile app development services for iOS and Android. We build scalable, high-performance mobile applications with modern technologies, seamless UX, and global deployment readiness.', 'mobile app development company, iOS app development, Android app developers, React Native app development, Flutter app development, mobile app agency, custom mobile apps, startup app development', NULL, NULL, NULL, 'index,follow', NULL, 'Mobile App Development Services | HilDes', 'Build scalable and high-performance mobile apps for iOS and Android with expert development and modern technologies.', NULL, NULL, 'https://www.hildes.io/assets/og/mobile-app-development.jpg', 'Mobile App Development Services | HilDes', 'Custom mobile app development for iOS and Android designed for performance, scalability, and user experience.', 'https://www.hildes.io/assets/og/mobile-app-development.jpg', NULL, '{\n    \"@context\": \"https://schema.org\",\n    \"@graph\": [\n        {\n            \"@type\": \"Service\",\n            \"name\": \"Mobile App Development\",\n            \"provider\": {\n                \"@type\": \"Organization\",\n                \"name\": \"HilDes\",\n                \"url\": \"https://www.hildes.io\",\n                \"address\": {\n                    \"@type\": \"PostalAddress\",\n                    \"addressLocality\": \"Lahore\",\n                    \"addressCountry\": \"Pakistan\"\n                }\n            },\n            \"serviceType\": \"Mobile Application Development\",\n            \"url\": \"https://www.hildes.io/mobile-app-development\",\n            \"description\": \"HilDes provides mobile app development services for iOS and Android, building scalable, secure, and high-performance applications for startups and enterprises.\",\n            \"areaServed