cceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>Yes, we specialize in MVP apps for startups to validate ideas quickly.</p>\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Do you handle backend development?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>Yes, we build complete systems including backend APIs and cloud infrastructure.</p>\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Will my app be scalable?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>Yes, we design apps with scalable architecture for future growth.</p>\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Do you publish apps to stores?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"<p>Yes, we handle deployment to Apple App Store and Google Play Store.</p>\"\n                    }\n                }\n            ]\n        }\n    ]\n}', '2026-04-23 10:53:01', '2026-04-23 10:54:31'),
(15, 'App\\Models\\CmsPage', 1, 1, 1, 1, 'privacy-policy', 'https://www.hildes.io/privacy-policy', 'Privacy Policy | HilDes', 'Read the Privacy Policy of HilDes to understand how we collect, use, and protect your personal data when using our website and services.', 'privacy policy HilDes, data protection, user privacy, GDPR compliance, data security policy', 'HilDes', 'width=device-width, initial-scale=1.0', 'privacy policy HilDes', 'index, follow', 'website', 'Privacy Policy | HilDes', 'Learn how HilDes collects, uses, and protects your personal information.', 'https://www.hildes.io/privacy-policy', 'HilDes', 'https://www.hildes.io/og-image.jpg', 'Privacy Policy | HilDes', 'Understand how your data is handled and protected at HilDes.', 'https://www.hildes.io/og-image.jpg', 'summary_large_image', '{\n    \"@context\": \"https://schema.org\",\n    \"@graph\": [\n        {\n            \"@type\": \"WebPage\",\n            \"name\": \"Privacy Policy | HilDes\",\n            \"url\": \"https://www.hildes.io/privacy-policy\",\n            \"description\": \"Privacy Policy explaining how HilDes collects, uses, and protects user data.\",\n            \"publisher\": {\n                \"@type\": \"Organization\",\n                \"name\": \"HilDes\",\n                \"logo\": {\n                    \"@type\": \"ImageObject\",\n                    \"url\": \"https://www.hildes.io/logo.png\"\n                }\n            }\n        },\n        {\n            \"@type\": \"FAQPage\",\n            \"faq_schema_version\": 1,\n            \"mainEntity\": [\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Does HilDes sell my personal data?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"No, HilDes does not sell or rent your personal information to third parties.\"\n                    }\n                },\n                {\n                    \"