(16, 'App\\Models\\CmsPage', 2, 1, 1, 1, 'about', 'https://www.hildes.io/about', 'About HilDes | AI, SaaS & Custom Software Development Company', 'Discover HilDes, a software development company specializing in AI solutions, SaaS platforms, and scalable web & mobile applications. We help businesses build and grow digital products.', 'about HilDes, AI development company, SaaS development, custom software development, web development agency, mobile app development company', 'HilDes', 'width=device-width, initial-scale=1.0', 'about HilDes', 'index, follow', 'website', 'About HilDes | AI, SaaS & Software Development Experts', 'Learn how HilDes helps startups and enterprises build scalable AI, SaaS, and custom software solutions.', 'https://www.hildes.io/about', 'HilDes', 'https://www.hildes.io/og-image.jpg', 'About HilDes | AI & SaaS Development Company', 'We build scalable AI systems, SaaS platforms, and custom applications for modern businesses.', 'https://www.hildes.io/og-image.jpg', 'summary_large_image', '{\n    \"@context\": \"https://schema.org\",\n    \"@graph\": [\n        {\n            \"@type\": \"Organization\",\n            \"name\": \"HilDes\",\n            \"url\": \"https://www.hildes.io/about\",\n            \"logo\": \"https://www.hildes.io/logo.png\",\n            \"description\": \"HilDes is a software development company specializing in AI solutions, SaaS platforms, and custom web and mobile applications.\",\n            \"foundingDate\": \"2024\",\n            \"areaServed\": \"Worldwide\",\n            \"contactPoint\": {\n                \"@type\": \"ContactPoint\",\n                \"contactType\": \"sales\",\n                \"email\": \"contact@hildes.io\"\n            },\n            \"sameAs\": [\n                \"https://www.linkedin.com/company/hildes\",\n                \"https://www.facebook.com/hildes\"\n            ]\n        },\n        {\n            \"@type\": \"FAQPage\",\n            \"faq_schema_version\": 1,\n            \"ma