(23, 'App\\Models\\CmsPage', 9, 1, 1, 1, 'faqs', 'https://www.hildes.io/faqs', 'FAQs | HilDes – AI, SaaS & Software Development Questions', 'Find answers to common questions about HilDes services including AI development, SaaS platforms, MVP development, pricing, timelines, and support.', 'HilDes FAQs, software development questions, AI development FAQ, SaaS development FAQ, MVP development questions, pricing software development', 'HilDes', 'width=device-width, initial-scale=1.0', 'HilDes FAQs', 'index, follow', 'website', 'FAQs | HilDes – Software Development Questions Answered', 'Explore frequently asked questions about AI, SaaS, and custom software development services at HilDes.', 'https://www.hildes.io/faqs', 'HilDes', 'https://www.hildes.io/og-image.jpg', 'FAQs | HilDes', 'Get answers about AI development, SaaS, MVPs, pricing, and timelines.', 'https://www.hildes.io/og-image.jpg', 'summary_large_image', '{\n    \"@context\": \"https://schema.org\",\n    \"@graph\": [\n        {\n            \"@type\": \"FAQPage\",\n            \"name\": \"FAQs | HilDes\",\n            \"url\": \"https://www.hildes.io/faqs\",\n            \"description\": \"Frequently asked questions about HilDes services, pricing, timelines, and technical expertise.\",\n            \"publisher\": {\n                \"@type\": \"Organization\",\n                \"name\": \"HilDes\",\n                \"logo\": {\n                    \"@type\": \"ImageObject\",\n                    \"url\": \"https://www.hildes.io/logo.png\"\n                }\n            },\n            \"faq_schema_version\": 1,\n            \"mainEntity\": [\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"What services does HilDes provide?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"HilDes provides AI development, SaaS platforms, MVP development, and custom software solutions.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"How long does it take to build an MVP?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"Typically, MVP development takes between 4 to 8 weeks depending on complexity.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Do you provide ongoing support?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"Yes, we offer post-launch support and SLA-based maintenance services.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"What industries do you work with?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"We work across multiple industries including startups, SaaS businesses, and enterprises.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"How do I get started?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"You can contact HilDes through the website to discuss your project and receive a proposal.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"What does HilDes do?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"HilDes is a software development company specializing in AI solutions, SaaS platforms, MVP development, and custom web and mobile applications.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Who do you work with?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"We work with startups, growing businesses, and enterprises looking to build or scale digital products.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Do you build AI-powered applications?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"Yes, we develop AI systems including RAG-based solutions, automation tools, and intelligent workflows.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Can you build a SaaS product from scratch?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"Yes, we design and develop scalable SaaS platforms, including multi-tenant architecture and subscription systems.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Do you offer MVP development?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"Yes, we help startups quickly build MVPs to validate ideas and enter the market faster.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"How long does a project take?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"Project timelines depend on complexity. MVPs typically take 4\\u20138 weeks, while larger systems may take several months.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"What development process do you follow?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"We follow an agile methodology with iterative development, regular updates, and continuous feedback.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"How much does a project cost?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"Costs vary depending on scope, features, and complexity. We provide custom quotes after understanding your requirements.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Do you offer fixed pricing or hourly models?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"We offer both fixed-price and flexible engagement models depending on the project.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Do you provide post-launch support?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"Yes, we offer maintenance, updates, and scaling support after deployment.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Do you provide SLA-based support?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"Yes, we provide SLA-based support with defined uptime and response times.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"What technologies do you use?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"We use modern technologies such as React.js, Next.js, Node.js, Fastify, MongoDB, and AI frameworks.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Can you scale applications as traffic grows?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"Yes, we design systems with scalability in mind to handle increasing users and data loads.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"How do you ensure data security?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"We follow best practices including secure coding, encryption, and access control.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Do you sign NDAs?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"Yes, we can sign NDAs to protect your business ideas and data.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"How can I start a project with HilDes?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"You can contact us via our website or email to discuss your requirements and get a proposal.\"\n                    }\n                },\n                {\n                    \"@type\": \"Question\",\n                    \"name\": \"Do you provide consultation?\",\n                    \"acceptedAnswer\": {\n                        \"@type\": \"Answer\",\n                        \"text\": \"Yes, we offer consultation to help you plan and define your project.\"\n                    }\n                }\n            ],\n            \"hasPart\": [\n                {\n                    \"@type\": \"FAQPage\",\n                    \"name\": \"General Questions\",\n                    \"mainEntity\": [\n                        {\n                            \"@type\": \"Question\",\n                            \"name\": \"What does HilDes do?\",\n                            \"acceptedAnswer\": {\n                                \"@type\": \"Answer\",\n                                \"text\": \"HilDes is a software development company specializing in AI solutions, SaaS platforms, MVP development, and custom web and mobile applications.\"\n                            }\n                        },\n                        {\n                            \"@type\": \"Question\",\n                            \"name\": \"Who do you work with?\",\n                            \"acceptedAnswer\": {\n                                \"@type\": \"Answer\",\n                                \"text\": \"We work with startups, growing businesses, and enterprises looking to build or scale digital products.\"\n                            }\n                        }\n                    ]\n                },\n                {\n                    \"@type\": \"FAQPage\",\n                    \"name\": \"Services & Expertise\",\n                    \"mainEntity\": [\n                        {\n                            \"@type\": \"Question\",\n                            \"name\": \"Do you build AI-powered applications?\",\n                            \"accepte