swer\": {\n                            \"@type\": \"Answer\",\n                            \"text\": \"Yes, we provide both fixed-price and flexible pricing models based on project needs.\"\n                        }\n                    }\n                ]\n            }\n        }\n    ]\n}', '2026-04-30 10:05:40', '2026-04-30 10:05:40'),
(26, 'App\\Models\\CmsPage', 12, 1, 1, 1, 'careers', 'https://www.hildes.io/careers', 'Careers at HilDes | Join Our AI & Software Development Team', 'Explore career opportunities at HilDes. Join our team to work on AI, SaaS, and cutting-edge software development projects.', 'careers HilDes, software developer jobs, AI jobs, SaaS developer jobs, remote developer jobs, tech careers', 'HilDes', 'width=device-width, initial-scale=1.0', 'careers HilDes', 'index, follow', 'website', 'Careers at HilDes | Join Our Team', 'Work on AI, SaaS, and innovative software projects with HilDes. Explore open roles and grow your career.', 'https://www.hildes.io/careers', 'HilDes', 'https://www.hildes.io/og-image.jpg', 'Careers at HilDes', 'Join HilDes and work on cutting-edge AI and SaaS projects.', 'https://www.hildes.io/og-image.jpg', 'summary_large_image', '{\n    \"@context\": \"https://schema.org\",\n    \"@type\": \"WebPage\",\n    \"name\": \"Careers at HilDes\",\n    \"url\": \"https://www.hildes.io/careers\",\n    \"description\": \"Explore career opportunities at HilDes in AI, SaaS, and software development.\",\n    \"publisher\": {\n        \"@type\": \"Organization\",\n        \"name\": \"HilDes\",\n        \"logo\": {\n            \"@type\": \"ImageObject\",\n            \"url\": \"https://www.hildes.io/logo.png\"\n        }\n    },\n    \"hiringOrganization\": {\n        \"@type\": \"Organization\",\n        \"name\": \"HilDes\",\n        \"sameAs\": \"https://www.hildes.io\"\n    },\n    \"mainEntity\": {\n        \"@type\": \"FAQPage\",\n        \"mainEntity\": [\n            {\n                \"@type\": \"Question\",\n                \"name\": \"What kind of roles does HilDes offer?\",\n                \"acceptedAnswer\": {\n                    \"@type\": \"Answer\",\n                    \"text\": \"HilDes offers roles in frontend, backend, full-stack development, AI engineering, mobile development, and DevOps.\"\n                }\n            },\n            {\n                \"@type\": \"Question\",\n                \"name\": \"Do you offer remote opportunities?\",\n                \"acceptedAnswer\": {\n                    \"@type\": \"Answer\",\n                    \"text\": \"Yes, depending on the role, remote or flexible work options may be available.\"\n                }\n            },\n            {\n                \"@type\": \"Question\",\n                \"name\": \"What technologies should I know?\",\n                \"acceptedAnswer\": {\n                    \"@type\": \"Answer\",\n                    \"text\": \"Familiarity with modern technologies like React.js, Node.js, and cloud-based systems is preferred.\"\n                }\n            },\n            {\n                \"@type\": \"Question\",\n                \"name\": \"How can I apply?\",\n                \"acceptedAnswer\": {\n                    \"@type\": \"Answer\",\n                    \"text\": \"You can apply through the careers page or contact us with your resume and portfolio.\"\n                }\n            },\n            {\n                \"@type\": \"Question\",\n                \"name\": \"What is the hiring process like?\",\n                \"acceptedAnswer\": {\n                    \"@type\": \"Answer\",\n                    \"text\": \"The process includes application review, technical evaluation, interviews, and final selection.\"\n                }\n            }\n        ]\n    }\n}', '2026-04-30 10:08:32', '2026-04-30 10:08:32'),
(27, 'App\\Models\\Job', 1, 1, 1, 1, 'bdm-intern-may-2026', 'https://www.hildes.io/careers#bdm-intern-may-2026', 'BDM Intern | HilDes', 'Business development internship at HilDes. 6-hour day (10 AM–4 PM). Apply by 30 May 2026.', 'BDM intern, HilDes, internship', 'HilDes', 'width=device-width, initial-scale=1.0', 'BDM intern', 'index, follow', 'website', 'BDM Intern | HilDes', 'Business development internship at HilDes. 6-hour day (10 AM–4 PM). Apply by 30 May 2026.', 'https://www.hildes.io/careers#bdm-intern-may-2026', 'HilDes', 'https://www.hildes.io/og-image.jpg', 'BDM Intern | HilDes', 'Business development internship at HilDes. 6-hour day (10 AM–4 PM). Apply by 30 May 2026.', 'https://www.hildes.io/og-image.jpg', 'summary_large_image', '{\n    \"@context\": \"https://schema.org\",\n    \"@type\": \"JobPosting\",\n    \"title\": \"BDM Intern\",\n    \"description\": \"Working hours: 10:00 AM – 4:00 PM (6 hours per day), Monday to Friday.Apply by: 30 May 2026.Join HilDes as a Business Development intern and learn how we position AI, SaaS, and MVP offerings to clients. You will work closely with senior BD team members on pipeline hygiene, outreach sequences, and market mapping.What you will learn: Pipeline research, outreach messaging, CRM hygiene, and how BD supports AI, SaaS, and MVP engagements at HilDes.\\n\\nSupport lead research and list building; assist with CRM updates and follow-ups; help prepare decks and meeting notes; shadow calls and demos where appropriate; contribute to partner and client outreach campaigns under supervision.\\n\\nPursuing or completed a bachelor\'s degree in Business Administration, Marketing, Commerce, or a related field.\\n\\nStrong communication and interpersonal skills; comfortable with email and phone outreach; MS Excel / Google Sheets; curiosity about B2B sales and partnerships; organized and detail-oriented.\",\n    \"identifier\": {\n        \"@type\": \"PropertyValue\",\n        \"name\": \"HilDes\",\n        \"value\": \"bdm-intern-may-2026\"\n    },\n    \"url\": \"https://www.hildes.io/careers#bdm-intern-may-2026\",\n    \"datePosted\": \"2026-05-01T05:26:31+00:00\",\n    \"employmentType\": \"INTERN\",\n    \"hiringOrganization\": {\n        \"@type\": \"Organization\",\n        \"name\": \"HilDes\",\n        \"sameAs\": \"https://www.hildes.io\",\n        \"logo\": {\n            \"@type\": \"ImageObject\",\n            \"url\": \"https://www.hildes.io/logo.png\"\n        }\n    },\n    \"jobLocation\": {\n        \"@type\": \"Place\",\n        \"address\": {\n            \"@type\": \"PostalAddress\",\n            \"addressCountry\": \"PK\",\n            \"streetAddress\": \"Hybrid (as agreed)\"\n        }\n    },\n    \"industry\": \"Information Technology & Services\",\n    \"occupationalCategory\": \"Business Development\",\n    \"workHours\": \"Mo,Tu,We,Th,Fr 10:00-16:00\",\n    \"qualifications\": \"Pursuing or completed a bachelor\'s degree in Business Administration, Marketing, Commerce, or a related field.\\n\\nStrong communication and interpersonal skills; comfortable with email and phone outreach; MS Excel / Google Sheets; curiosity about B2B sales and partnerships; organized and detail-oriented.\",\n    \"responsibilities\": \"Support lead research and list building; assist with CRM updates and follow-ups; help prepare decks and meeting notes; shadow calls and demos where appropriate; contribute to partner and client outreach campaigns under supervision.\",\n    \"skills\": \"Strong communication and interpersonal skills; comfortable with email and phone outreach; MS Excel / Google Sheets; curiosity about B2B sales and partnerships; organized and detail-oriented.\",\n    \"validThrough\": \"2026-05-30T23:59:59Z\"\n}', '2026-05-01 00:26:31', '2026-05-01 00:35:02'),
(28, 'App\\Models\\Job', 2, 1, 1, 1, 'digital-marketing-intern-may-2026', 'https://www.hildes.io/careers#digital-marketing-intern-may-2026', 'Digital Marketing Intern | HilDes', 'Digital marketing internship at HilDes. 6-hour day (10 AM–4 PM). Apply by 30 May 2026.', 'digital marketing intern, HilDes, internship', 'HilDes', 'width=device-width, initial-scale=1.0', 'digital marketing intern', 'index, follow', 'website', 'Digital Marketing Intern | HilDes', 'Digital marketing internship at HilDes. 6-hour day (10 AM–4 PM). Apply by 30 May 2026.', 'https://www.hildes.io/careers#digital-marketing-intern-may-2026', 'HilDes', 'https://www.hildes.io/og-image.jpg', 'Digital Marketing Intern | HilDes', 'Digital marketing internship at HilDes. 6-hour day (10 AM–4 PM). Apply by 30 May 2026.', 'https://www.hildes.io/og-image.jpg', 'summary_large_image', '{\n    \"@context\": \"https://schema.org\",\n    \"@type\": \"JobPosting\",\n    \"title\": \"Digital Marketing Intern\",\n    \"description\": \"Working hours: 10:00 AM – 4:00 PM (6 hours per day), Monday to Friday.Apply by: 30 May 2026.Support HilDes marketing across organic channels, campaigns, and brand touchpoints for AI, SaaS, and software services. Ideal if you want hands-on experience with modern growth stacks.What you will learn: Organic growth tactics, campaign reporting, on-page SEO checks, and content workflows for technology products.\\n\\nAssist with social content scheduling and drafts; support on-page SEO checks and content updates; help track campaign metrics; contribute to email and landing page copy reviews; support event and launch announcements.\\n\\nPursuing or completed a bachelor\'s in Marketing, Communications, Media, or a related field.\\n\\nBasic understanding of SEO, social media, and content formats; familiarity with Canva or similar tools; good writing in English; willingness to learn analytics and campaign reporting.\",\n    \"identifier\": {\n        \"@type\": \"PropertyValue\",\n        \"name\": \"HilDes\",\n        \"value\": \"digital-marketing-intern-may-2026\"\n    },\n    \"url\": \"https://www.hildes.io/careers#digital-marketing-intern-may-2026\",\n    \"datePosted\": \"2026-05-01T05:26:31+00:00\",\n    \"employmentType\": \"INTERN\",\n    \"hiringOrganization\": {\n        \"@type\": \"Organization\",\n        \"name\": \"HilDes\",\n        \"sameAs\": \"https://www.hildes.io\",\n        \"logo\": {\n            \"@type\": \"ImageObject\",\n            \"url\": \"https://www.hildes.io/logo.png\"\n        }\n    },\n    \"jobLocation\": {\n        \"@type\": \"Place\",\n        \"address\": {\n            \"@type\": \"PostalAddress\",\n            \"addressCountry\": \"PK\",\n            \"streetAddress\": \"Hybrid (as agreed)\"\n        }\n    },\n    \"industry\": \"Information Technology & Services\",\n    \"occupationalCategory\": \"Marketing\",\n    \"workHours\": \"Mo,Tu,We,Th,Fr 10:00-16:00\",\n    \"qualifications\": \"Pursuing or completed a bachelor\'s in Marketing, Communications, Media, or a related field.\\n\\nBasic understanding of SEO, social media, and content formats; familiarity with Canva or similar tools; good writing in English; willingness to learn analytics and campaign reporting.\",\n    \"responsibilities\": \"Assist with social content scheduling and drafts; support on-page SEO checks and content updates; help track campaign metrics; contribute to email and landing page copy reviews; support event and launch announcements.\",\n    \"skills\": \"Basic understanding of SEO, social media, and content formats; familiarity with Canva or similar tools; good writing in English; willingness to learn analytics and campaign reporting.\",\n    \"validThrough\": \"2026-05-30T23:59:59Z\"\n}', '2026-05-01 00:26:31', '2026-05-01 00:35:02');

